mapper.sql:
WHERE m.deleted_at IS NULL
        AND (#{platform} = TRUE OR m.tenant_id = #{tenantId})
        AND m.tenant_id = #{tenantId}

            AND (m.model_code ILIKE CONCAT('%', #{keyword}, '%')
                 OR m.display_name ILIKE CONCAT('%', #{keyword}, '%'))

        AND m.publish_status = #{status}

mapper.select:
SELECT COUNT(*) FROM tenant_model
WHERE tenant_id = #{tenantId} AND model_code = #{modelCode} AND deleted_at IS NULL
AND id <> #{excludeId}
